package com.example.auth

import android.content.Context
import android.content.SharedPreferences

data class AuthSession(
    val authToken: String,
    val userId: String
)

class AuthenticationManager(context: Context) {

    companion object {
        private const val PREFS_NAME = "auth_prefs"
        private const val KEY_AUTH_TOKEN = "key_auth_token"
        private const val KEY_USER_ID = "key_user_id"
    }

    private val sharedPreferences: SharedPreferences =
        context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)

    @Synchronized
    fun saveAuthSession(authToken: String, userId: String) {
        sharedPreferences.edit()
            .putString(KEY_AUTH_TOKEN, authToken)
            .putString(KEY_USER_ID, userId)
            .apply()
    }

    @Synchronized
    fun isLoggedIn(): Boolean {
        return !getAuthToken().isNullOrBlank() && !getUserId().isNullOrBlank()
    }

    @Synchronized
    fun getAuthToken(): String? {
        return sharedPreferences.getString(KEY_AUTH_TOKEN, null)
    }

    @Synchronized
    fun getUserId(): String? {
        return sharedPreferences.getString(KEY_USER_ID, null)
    }

    @Synchronized
    fun getAuthSession(): AuthSession? {
        val token = getAuthToken()
        val userId = getUserId()
        return if (!token.isNullOrBlank() && !userId.isNullOrBlank()) {
            AuthSession(token, userId)
        } else {
            null
        }
    }

    @Synchronized
    fun clearAuthSession() {
        sharedPreferences.edit()
            .remove(KEY_AUTH_TOKEN)
            .remove(KEY_USER_ID)
            .apply()
    }
}